mapper.select:
SELECT p.project_id, p.project_title, p.project_describe, p.created_at, p.finish_date, CASE WHEN p.finish_date IS NOT NULL AND p.finish_date <= TRUNC(SYSDATE) THEN '완료'
WHEN EXISTS ( SELECT 1 FROM task t WHERE t.project_id = p.project_id ) THEN '진행 중'
ELSE '신규' END AS status FROM project p WHERE p.project_id = #{projectId}

SELECT module_name
FROM module_mapping
WHERE project_id = #{projectId}

mapper.update:
UPDATE project
SET project_title = #{projectTitle},
	project_describe = #{projectDescribe}
WHERE project_id = #{projectId}

mapper.insert:
INSERT INTO module_mapping (
				module_map_id,
				project_id,
				module_name
							)
VALUES (
				(SELECT NVL(MAX(module_map_id), 0) + 1 FROM module_mapping),
				#{projectId},
				#{moduleCode}
		)

mapper.update:
UPDATE module_mapping
SET is_active = #{isActive}
WHERE project_id = #{projectId}
  AND module_name = #{moduleName}

mapper.select:
SELECT COUNT(*)
FROM module_mapping
WHERE project_id = #{projectId}
  AND module_name = #{moduleName}
  AND is_active   = 'Y'

SELECT DISTINCT rp.permission_code
FROM members m
JOIN member_roles mr ON m.member_id = mr.member_id
JOIN role_permissions rp ON mr.role_id = rp.role_id
WHERE m.user_code = #{userCode}
  AND m.project_id = #{projectId}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM members
WHERE user_code = #{userCode}
  AND project_id = #{projectId}

SELECT * FROM ( SELECT p.project_id AS projectId, p.project_title AS projectTitle, p.status, p.created_at AS createdAt, ROWNUM AS rn FROM project p JOIN members m ON p.project_id = m.project_id WHERE m.user_code = #{userCode}
AND p.project_title LIKE '%' || #{keyword} || '%'
ORDER BY p.project_id DESC ) WHERE rn > #{offset} AND rn <= #{offset} + #{pageSize}
